import React, {type FC, type PropsWithChildren, useCallback, useMemo, useState} from "react";
import type {IKitsContainer} from "@lmb-it/kitsconcerto-types";
import ErrorMessage from "../ErrorMessage";
import {Flex, Text} from "../../../_compat";
import {uniqueId} from "lodash";
import Label from "../Label";
import {useComponentDefaults, useResolvedStyle, useResolvedElementStyles} from "../../../hooks";

/**
 * KitsContainer — wraps all form inputs with label, addons, helper text, and errors.
 *
 * Supports element-level styling via the `elementStyles` prop, which is passed
 * from the parent form input component (resolved from theme.components[name].elements).
 *
 * Element slots applied here:
 *   container  → outer Flex wrapper
 *   label      → Label component
 *   inputGroup → input group Flex (around addons + input)
 *   leftAddon  → left addon wrapper
 *   rightAddon → right addon wrapper
 *   helperText → helper text element
 *   error      → error message element
 *
 * The `root` slot is NOT applied here — it is applied by the parent form input
 * component directly to the PrimeReact/native input element.
 */
const KitsContainer: FC<PropsWithChildren<IKitsContainer>> = (rawProps) => {
    const {mergedProps: props, themeStyle, elementStyles: ownElementStyles} = useComponentDefaults('FormContainer', rawProps);
    const resolvedThemeStyle = useResolvedStyle(themeStyle);

    const {
        id,
        helperText,
        className,
        children,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        required,
        hideError,
        additionalClassName,
        label,
        isFloatedLabel,
        containerStyle,
        inputSize,
        bare,
        elementStyles: parentElementStyles,
    } = props;

    // Merge raw IStyleClasses: FormContainer's own (lower priority) < parent-passed (higher)
    // Then resolve once to platform-appropriate styles
    const elStyles = useResolvedElementStyles(useMemo(() => {
        const merged: Record<string, Record<string, any>> = {};
        // Collect all slot keys from both sources
        const allKeys = new Set([
            ...Object.keys(ownElementStyles || {}),
            ...Object.keys(parentElementStyles || {}),
        ]);
        for (const key of allKeys) {
            merged[key] = {
                ...(ownElementStyles?.[key] || {}),
                ...(parentElementStyles?.[key] || {}),
            };
        }
        return merged;
    }, [ownElementStyles, parentElementStyles]));

    const elementId = id ? `${id}_element` : uniqueId('element_');
    const mainClassName = className ? className + (required ? ' required_field' : '') : (required ? 'required_field' : '')

    const classNameMerge = additionalClassName ?? "";

    const [isFocused, setIsFocused] = useState(false);
    const handleFocus = useCallback(() => setIsFocused(true), []);
    const handleBlur = useCallback((e: React.FocusEvent<HTMLDivElement>) => {
        if (!e.currentTarget.contains(e.relatedTarget as Node)) {
            setIsFocused(false);
        }
    }, []);

    const inputGroupClass = useMemo(() => {
        if (bare) return classNameMerge || undefined;
        const out = ["p-inputgroup"];
        if (classNameMerge) out.push(classNameMerge);
        if (invalid) out.push("p-invalid");
        if (isFocused) out.push("kits-focused");
        if (inputSize === "sm") out.push("p-inputtext-sm");
        if (inputSize === "lg") out.push("p-inputtext-lg");
        return out.join(" ");
    }, [bare, classNameMerge, invalid, isFocused, inputSize]);

    const bareInputGroupStyle: React.CSSProperties | undefined = bare
        ? { borderWidth: 0, borderRadius: 0, overflow: 'visible', boxShadow: 'none', outline: 'none' }
        : undefined;

    return (
        <Flex
            gap={3}
            w={"full"}
            h={"auto"}
            flexDirection={"column"}
            className={mainClassName}
            id={elementId}
            // @ts-ignore
            style={elStyles.container || undefined}
        >
            {!isFloatedLabel && (
                <Label
                    label={label}
                    elementId={elementId}
                    required={required}
                    style={elStyles.label || undefined}
                />
            )}

            <Flex
                flexDirection={"row"}
                w={"full"}
                h={bare ? undefined : "full"}
                overflow={bare ? undefined : "hidden"}
                className={inputGroupClass}
                //@ts-ignore
                style={bare?{}:{
                    ...(Object.keys(resolvedThemeStyle).length ? resolvedThemeStyle : {}),
                    ...containerStyle,
                    ...(elStyles.inputGroup || {}),
                }}
                onFocus={handleFocus}
                onBlur={handleBlur}
            >
                {leftAddon && (
                    <Flex
                        className="p-inputgroup-addon"
                        // @ts-ignore
                        style={{border: 'none', borderRadius: 0, ...(elStyles.leftAddon || {})}}
                    >
                        {typeof leftAddon === "string"
                            ? <span style={{paddingBottom:4}}>{leftAddon}</span>
                            : React.isValidElement(leftAddon)
                                ? leftAddon
                                : null}
                    </Flex>
                )}

                {!!label && isFloatedLabel && (
                    <span className="p-float-label w-full h-full">
            {children}
                        {isFloatedLabel && (
                            <Label
                                label={label}
                                elementId={elementId}
                                required={required}
                                style={elStyles.label || undefined}
                            />
                        )}
          </span>
                )}

                {!!label && !isFloatedLabel && children}
                {!label && children}

                {rightAddon && (
                    <Flex
                        className="p-inputgroup-addon"
                        // @ts-ignore
                        style={{border: 'none', borderRadius: 0, ...(elStyles.rightAddon || {})}}
                    >
                        {typeof rightAddon === "string"
                            ? <span style={{paddingBottom:4}}>{rightAddon}</span>
                            : React.isValidElement(rightAddon)
                                ? rightAddon
                                : null}
                    </Flex>
                )}
            </Flex>
            {helperText && typeof helperText != "function" && (
                <Text fontSize={10} as={"small"} style={elStyles.helperText || undefined}>
                    {helperText}
                </Text>
            )}
            {!hideError && <ErrorMessage invalid={invalid} errors={errors} style={elStyles?.error || undefined}/>}
        </Flex>
    );
};

export default KitsContainer;
